+fn json_compound_placeholder_closure_artifact_dir() -> PathBuf {
+    std::env::var_os("RGC_JSON_COMPOUND_PLACEHOLDER_CLOSURE_ARTIFACT_DIR")
+        .map(PathBuf::from)
